CREATE TABLE IF NOT EXISTS `channel_routing_state` (`channel_id` INT NOT NULL PRIMARY KEY, `success_alpha` DOUBLE NOT NULL DEFAULT 2, `success_beta` DOUBLE NOT NULL DEFAULT 2, `latency_log_mu` DOUBLE NOT NULL DEFAULT 0, `latency_log_sigma2` DOUBLE NOT NULL DEFAULT 0.8, `latency_n` INT NOT NULL DEFAULT 0, `prompt_ewma` DOUBLE NOT NULL DEFAULT 0, `completion_ewma` DOUBLE NOT NULL DEFAULT 0, `cache_read_ewma` DOUBLE NOT NULL DEFAULT 0, `cache_creation_ewma` DOUBLE NOT NULL DEFAULT 0, `pricing_snapshot` JSON, `manual_weight` DOUBLE NOT NULL DEFAULT 1, `version` INT NOT NULL DEFAULT 1, `updated_at` VARCHAR(191) DEFAULT (DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')), FOREIGN KEY (`channel_id`) REFERENCES `route_channels`(`id`) ON DELETE CASCADE);
CREATE INDEX `channel_routing_state_updated_at_idx` ON `channel_routing_state` (`updated_at`);
